const path = require('path');
const fs = require('fs');

// Load problems data once
const problemsDataPath = path.resolve(__dirname, '../../data/problems.json');
let problemsData = [];
try {
  const rawData = fs.readFileSync(problemsDataPath, 'utf8');
  problemsData = JSON.parse(rawData);
} catch (e) {
  // If file read fails, keep problemsData empty
  problemsData = [];
}

/**
 * Get problem details by problemId including component statistics.
 * @param {string|number} problemId
 * @returns {object} problem details with component stats or null if not found
 */
function getProblemDetails(problemId) {
  // Find problem by id (string or number)
  const problem = problemsData.find(p => String(p.id) === String(problemId));
  if (!problem) {
    return null;
  }

  // Aggregate component statistics
  // Components are expected to be an array of objects with language, status, and points
  const components = problem.components || [];

  const languageCounts = {};
  const statusCounts = {};
  let maxPoints = 0;

  components.forEach(component => {
    const lang = component.language || 'unknown';
    const status = component.status || 'unknown';
    const points = Number(component.points) || 0;

    languageCounts[lang] = (languageCounts[lang] || 0) + 1;
    statusCounts[status] = (statusCounts[status] || 0) + 1;
    if (points > maxPoints) {
      maxPoints = points;
    }
  });

  // Return problem details with aggregated stats
  return {
    ...problem,
    componentStats: {
      languageCounts,
      statusCounts,
      maxPoints
    }
  };
}

module.exports = {
  getProblemDetails
};
