const ProblemsService = require('../services/ProblemsService');

/**
 * Controller handler for GET /api/v1/problems/:problemId
 * Returns problem details with component statistics or 404 error if not found
 */
async function getProblemDetail(req, res) {
  const problemId = req.params.problemId;

  const problemDetails = ProblemsService.getProblemDetails(problemId);

  if (!problemDetails) {
    return res.status(404).json({ error: 'Problem not found' });
  }

  return res.json(problemDetails);
}

module.exports = {
  getProblemDetail
};
